body:
The following index definition example uses the
sample\_mflix.movies collection to index a field as multiple types. The
following index definition indexes the `title` field as the following
types:

- `autocomplete` type to support autocompletion for queries using
  the [autocomplete](autocomplete-ref) operator.

- `string` type to support text search using operators such
  [text](text-ref), [Phrase](phrase-ref), and so on.

```go
package main

import (
	"context"
	"fmt"
	"log"

	"go.mongodb.org/mongo-driver/v2/bson"
	"go.mongodb.org/mongo-driver/v2/mongo"
	"go.mongodb.org/mongo-driver/v2/mongo/options"
)

func main() {
	ctx := context.Background()
	uri := "<connection-string>"
	client, err := mongo.Connect(options.Client().
		ApplyURI(uri))
	if err != nil {
		panic(err)
	}

	defer func() {
		if err := client.Disconnect(context.TODO()); err != nil {
			panic(err)
		}
	}()

	coll := client.Database("sample_mflix").Collection("movies")
	const indexName = "default"
	opts := options.SearchIndexes().SetName(indexName).SetType("search")

	// Define the MongoDB Search index for the autocomplete field
	searchIndexModel := mongo.SearchIndexModel{
		Definition: bson.D{
			{"mappings", bson.D{
				{"dynamic", false},
				{"fields", bson.D{
					{"title", bson.A{
						bson.D{
							{"type", "autocomplete"},
							{"analyzer", "lucene.standard"},
							{"tokenization", "edgeGram"},
							{"minGrams", 2},
							{"maxGrams", 15},
							{"foldDiacritics", false},
						},
						bson.D{{"type", "string"}},
					}},
				}},
			}},
		},
		Options: opts,
	}

	// Create the index
	searchIndexName, err := coll.SearchIndexes().CreateOne(ctx, searchIndexModel)
	if err != nil {
		log.Fatalf("Failed to create the Atlas Search index: %v", err)
	}

	fmt.Println("Name of index created: " + searchIndexName)
}

